from google.rpc import status_pb2, code_pb2

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class AuthorizationService(external_auth_pb2_grpc.AuthorizationServicer):
    def __init__(self, allowed_tokens: Set[str] = None, required_headers: Dict[str, str] = None):
        self.allowed_tokens = allowed_tokens or {"valid-token-123", "admin-token-456"}
        self.required_headers = required_headers or {}
        
    def Check(self, request: external_auth_pb2.CheckRequest, context):
        logger.info("Received CheckRequest")
        
        http_request = request.attributes.request.http
        headers = http_request.headers
        
        logger.info(f"Request path: {http_request.path}")
        logger.info(f"Request method: {http_request.method}")
        logger.info(f"Headers: {dict(headers)}")
        
        auth_header = headers.get("authorization", "")
        
        if not auth_header:
            logger.warning("No authorization header found")
            return self._deny_response("Missing authorization header", 401)
        
        token = self._extract_token(auth_header)
        
        if not token:
            logger.warning("Invalid authorization header format")
            return self._deny_response("Invalid authorization header format", 401)
        
        if token not in self.allowed_tokens:
            logger.warning(f"Invalid token: {token}")
            return self._deny_response("Unauthorized", 403)
        
        for header_name, required_value in self.required_headers.items():
            actual_value = headers.get(header_name.lower(), "")
            if actual_value != required_value:
                logger.warning(f"Required header {header_name} mismatch or missing")
                return self._deny_response(f"Missing or invalid header: {header_name}", 403)
        
        custom_user_id = headers.get("x-user-id", "unknown")
        
        logger.info(f"Authorization successful for user: {custom_user_id}")
        return self._allow_response(token, custom_user_id)
    
    def _extract_token(self, auth_header: str) -> str:
        if auth_header.startswith("Bearer "):
            return auth_header[7:]
        return ""
    
    def _allow_response(self, token: str, user_id: str):
        response = external_auth_pb2.CheckResponse()
        response.status.code = code_pb2.OK
        
        ok_response = external_auth_pb2.OkHttpResponse()
        
        header_user = external_auth_pb2.HeaderValueOption()
        header_user.header.key = "x-auth-user"
        header_user.header.value = user_id
        ok_response.headers.append(header_user)
        
        header_token_validated = external_auth_pb2.HeaderValueOption()
        header_token_validated.header.key = "x-token-validated"
        header_token_validated.header.value = "true"
        ok_response.headers.append(header_token_validated)
        
        response.ok_response.CopyFrom(ok_response)
        
        return response
    
    def _deny_response(self, message: str, status_code: int = 403):
        response = external_auth_pb2.CheckResponse()
        
        denied_response = external_auth_pb2.DeniedHttpResponse()
        denied_response.status.code = status_code
        denied_response.body = message
        
        header_content_type = external_auth_pb2.HeaderValueOption()
        header_content_type.header.key = "content-type"
        header_content_type.header.value = "text/plain"
        denied_response.headers.append(header_content_type)
        
        response.denied_response.CopyFrom(denied_response)
        
        return response


def serve(port: int = 50051, max_workers: int = 10):
    server = grpc.server(futures.ThreadPoolExecutor(max_workers=max_workers))
    
    allowed_tokens = set(os.getenv("ALLOWED_TOKENS", "valid-token-123,admin-token-456").split(","))
    
    required_headers = {}
    required_headers_env = os.getenv("REQUIRED_HEADERS", "")
    if required_headers_env:
        for header_pair in required_headers_env.split(","):
            if ":" in header_pair:
                key, value = header_pair.split(":", 1)
                required_headers[key.strip()] = value.strip()
    
    auth_service = AuthorizationService(
        allowed_tokens=allowed_tokens,
        required_headers=required_headers
    )
    
    external_auth_pb2_grpc.add_AuthorizationServicer_to_server(
        auth_service, server
    )
    
    listen_addr = f'[::]:{port}'
    server.add_insecure_port(listen_addr)
    
    logger.info(f"Starting gRPC server on {listen_addr}")
    logger.info(f"Allowed tokens: {allowed_tokens}")
    logger.info(f"Required headers: {required_headers}")
    
    server.start()
    logger.info("Server started successfully")
    
    try:
        server.wait_for_termination()
    except KeyboardInterrupt:
        logger.info("Shutting down server")
        server.stop(0)


